.darma-loader-darma-custom-490 {color: var(--loader-color, #be123c);
   width: 80px;
   height: 70px;
   border-radius: 50%;
   border: 8px solid var(--loader-color, #be123c);
   box-sizing: border-box;
   --c:no-repeat radial-gradient(farthest-side, var(--loader-secondary-color, #fda4af) 94%,#0000);
   --b:no-repeat radial-gradient(farthest-side, currentColor 94%,#0000);
   background: var(--c) 11px 15px, var(--b) 6px 15px, var(--c) 35px 23px, var(--b) 29px 15px, var(--c) 11px 46px, var(--b) 11px 34px, var(--c) 36px 0px, var(--b) 50px 31px, var(--c) 47px 43px, var(--b) 31px 48px, var(--loader-color, #be123c);
   background-size: 15px 15px,6px 6px;
   animation: darma-loader-darma-custom-490-l4 3s infinite;
}
@keyframes darma-loader-darma-custom-490-l4  {
  0% {-webkit-mask:conic-gradient(#0000 0 ,currentColor 0)}
16.67% {-webkit-mask:conic-gradient(#0000 60deg ,currentColor 0)}
33.33% {-webkit-mask:conic-gradient(#0000 120deg,currentColor 0)}
50% {-webkit-mask:conic-gradient(#0000 180deg,currentColor 0)}
66.67% {-webkit-mask:conic-gradient(#0000 240deg,currentColor 0)}
83.33% {-webkit-mask:conic-gradient(#0000 300deg,currentColor 0)}
100% {-webkit-mask:conic-gradient(#0000 360deg,currentColor 0)}
}

